# CONTROL PANEL CONTROLS
# PRESS THE Nth BUTTON
mode_select_0 {
	+ keyboard	Zero
}

mode_select_1 {
	+ keyboard	1
	- keyboard	LeftShift
}

mode_select_2 {
	+ keyboard	2
	- keyboard	LeftShift
}

mode_select_3 {
	+ keyboard	3
	- keyboard	LeftShift
}

mode_select_4 {
	+ keyboard	4
	- keyboard	LeftShift
}

mode_select_5 {
	+ keyboard	5
	- keyboard	LeftShift
}

mode_select_6 {
	+ keyboard	6
	- keyboard	LeftShift
}

mode_select_7 {
	+ keyboard	7
	- keyboard	LeftShift
}

mode_select_8 {
	+ keyboard	8
	- keyboard	LeftShift
}

mode_select_9 {
	+ keyboard	9
	- keyboard	LeftShift
}






# GROUPING CONTROLS
# SELECT GROUP WITH A KEY
group_select_0 {
	+ keyboard	1
	+ keyboard	LeftShift
}

group_select_1 {
	+ keyboard	2
	+ keyboard	LeftShift
}

group_select_2 {
	+ keyboard	3
	+ keyboard	LeftShift
}

group_select_3 {
	+ keyboard	4
	+ keyboard	LeftShift
}

group_select_4 {
	+ keyboard	5
	+ keyboard	LeftShift
}

group_select_5 {
	+ keyboard	6
	+ keyboard	LeftShift
}

group_select_6 {
	+ keyboard	7
	+ keyboard	LeftShift
}






# THROTTLE CONTROLS
# DIGITAL THROTTLE TURBO
turbo {
	+ keyboard 	W
	- program	EditMode
}

# DIGITAL THROTTLE FORWARD
throttle_up {
	+ keyboard 	Q
	- program	EditMode
}

# DIGITAL THROTTLE BACK
throttle_down {
	+ keyboard 	R
	- program	EditMode
}

# STRAFING CONTROLS
# DIGITAL STRAFE RIGHT
strafe_right {
	+ keyboard 	S
	- program	EditMode
}

# DIGITAL STRAFE LEFT
strafe_left {
	+ keyboard 	A
	- program	EditMode
}

# JUMP CONTROLS
jump {
	+ keyboard 	F
	- keyboard	LeftControl
	- program	EditMode
}

# LINK SIMILAR WEAPONS
weapon_link {
	+ keyboard	Z
	- program	EditMode
}

# SELECT A PARTICULAR HARDPOINT
weapon_select_0 {
	+ keyboard	F8
	- keyboard	LeftShift
}

weapon_select_1 {
	+ keyboard	C
	- keyboard	LeftShift
}

weapon_select_2 {
	+ keyboard	X
	- keyboard	LeftShift
}

weapon_select_3 {
	+ keyboard	F11
	- keyboard	LeftShift
}

weapon_select_4 {
	+ keyboard	F12
	- keyboard	LeftShift
}









# MISCELLANEOUS CONTROLS
# EJECT FROM VEHICLE
eject {
	+ keyboard	B
	+ keyboard	LeftControl
	- program	EditMode
	- keyboard	LeftShift
}

# ABANDON VEHICLE
abandon {
	+ keyboard	H
	- program	EditMode
}

# DEPLOY/UNDEPLOY VEHICLE
deploy {
	+ keyboard	T
	- program	EditMode
}

# TARGETING CONTROLS
# TARGET THE FRONTAL OBJECT
frontal_target {
	+ keyboard	G
	- program	EditMode
}

# DROP A NAV BEACON
drop_beacon {
	+ keyboard	P
	- program	EditMode
}


# PRESS RETICLE COMMAND
menu_press {
	+ keyboard	Space
}

# PRESS TARGET COMMAND
alt_press {
	+ keyboard	Alt
}

# CLOAK VEHICLE
cloak {
        + keyboard      D
	- program	EditMode
}








# STEERING CONTROLS
# ANALOG STEER
steer {
	- mouse		HorizVel
	- program	ControlMode
}

# DIGITAL STEER RIGHT
steer_right {
	+ keyboard RightArrow
	- program   EditMode
}

# DIGITAL STEER LEFT
steer_left {
	+ keyboard LeftArrow
	- program   EditMode
}

# PITCHING CONTROLS
# ANALOG PITCH
pitch {
	+ mouse		VertPos
	- program	ControlMode
	- keyboard	Tab
}

# DIGITAL PITCH UP
pitch_up {
	+ keyboard Comma
	- program	EditMode
}

# DIGITAL PITCH DOWN
pitch_down {
	+ keyboard 	K
	- program	ControlMode
}









# TRIGGER SPECIAL WEAPON
weapon_special {
	+ mouse		MiddleBtn
	- keyboard	LeftShift
	- program	ControlMode
}

weapon_cycle {
	+ keyboard KeypadEnter
	- program	EditMode
}

# WEAPON CONTROLS
# TRIGGER CURRENT WEAPON
weapon_fire {
	+ mouse		LeftBtn
	- keyboard	LeftShift
	- program	ControlMode
}

weapon_fire {
	+ keyboard  	Insert
	- program	EditMode
}

# CYCLE WEAPON SELECTION
weapon_cycle {
	+ mouse		RightBtn
	- keyboard	LeftShift
	- program	ControlMode
}
# CYCLE THROUGH NAV BEACONS
cycle_beacon {
	+ keyboard	N
	- program	EditMode
}









# VIEWPOINT CONTROLS
# TRACK PITCH UP
track_pitch_plus {
	+ keyboard	GreyUpArrow
}

# TRACK PITCH DOWN
track_pitch_minus {
	+ keyboard	GreyDownArrow
}

# TRACK YAW RIGHT
track_yaw_plus {
	+ keyboard	GreyRightArrow
}

# TRACK YAW LEFT
track_yaw_minus {
	+ keyboard	GreyLeftArrow
}

# INCREASE ZOOM FACTOR
zoom_factor_plus {
	+ keyboard	GreyPlus
}

zoom_factor_plus {
	+ keyboard	Equal
}

# DECREASE ZOOM FACTOR
zoom_factor_minus {
	+ keyboard	GreyMinus
}

zoom_factor_minus {
	+ keyboard	Minus
}

# RESET ZOOM FACTOR
zoom_factor_reset {
	+ keyboard	GreyInsert
}










#Sat Mode Shit


# CENTER ON THE USER
center_player {
	+ keyboard	C
	+ program	ControlMode
	- program   EditMode
}

# CENTER ON THE RECYCLER
center_recycler {
	+ keyboard	R
	+ program	ControlMode
	- program   EditMode
}









